VALUES
  ('pukao-d0d1b9a2-moex-00274', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X1年度淨利為$800,000，X1年初以$2,000,000取得一棟供出租之商業大樓，採用成本模 式，X1年中由成本模式改為公允價值模式，後續衡量改變時該商業大樓之帳面金額為$1,800,000， X1年底公允價值為$2,000,000。請問甲公司X1年度「營業活動之淨現金流量」為多少？', '["$800,000", "$1,000,000", "$1,200,000", "$1,400,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00275', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X1年底普通股流通在外股數為150,000股，每股市價$95。當年度每股現金股利為$2.5， 股利支付率為40%，則甲公司X1年底的本益比為：', '["12", "15.2", "18.5", "19"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00276', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X1年初買了100頭綿羊，準備收成羊毛出售，當日每頭綿羊購價為$3,000，另購買時支 付運費$9,000。甲公司估計若立即出售該100頭綿羊，將支付運費$10,000及市場管理費等其他成 本$5,000，甲公司X1年初應認列該生物資產之金額為何？', '["$276,000", "$285,000", "$294,000", "$309,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e416025ce5d6", "answer_pdf_sha1": "02587aca6058", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00277', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'essay', '請依我國審計準則公報之相關規範，回答下列問題：
因受極端氣候變遷、貿易戰或疫情的影響，經濟經營環境可能充滿了
不確定性及不可預測性。涉及高度不確定性之會計估計事項將是查核
人員所高度關注的事項，故查核人員應複核管理階層作會計估計時之
判斷及決定，以辨認是否有管理階層偏頗之跡象。請問與會計估計有
關之管理階層偏頗跡象為何？請列舉三項說明之。（15 分）
集團主辦會計師如決定於集團查核報告之查核意見段及查核意見
之基礎段中提及組成個體查核人員之查核，應於其他事項段中敘
明。請問該其他事項段應敘明之內容為何？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00278', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'essay', '請依我國審計準則公報之相關規範，回答下列問題：
財務報導舞弊通常涉及管理階層踰越某些形式上有效運作之控制，請
問該管理階層踰越控制（Managementoverrideofcontrols）之舞弊，通
常係故意藉由那些方法為之？請列舉三項說明。（15 分）
查核人員對所有未回函之情況應執行替代查核程序，以取得攸關且可
靠之查核證據。請問有關「應收帳款」、「應付帳款」二科目之餘額，
查核人員可能執行之替代查核程序為何？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00279', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '會計師因查核範圍受到重大但未達廣泛的限制時，應出具何種意見之查核報告？', '["無保留意見", "保留意見", "否定意見", "無法表示意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00280', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列何者會計師會出具否定意見？', '["受查公司帳冊遭火災焚毀，會計師無法取得足夠查核證據", "受查公司已決定解散，仍然依繼續經營假設編製財務報表", "受查公司子公司之財務報表係由其他會計師查核", "會計師評估自己不具備獨立性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00281', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '依我國審計準則公報第59號「修正式意見之查核報告」之規範，會計師應就事項對財務報表之影 響或可能影響是否「廣泛」（Pervasive）而作判斷。下列敘述何者錯誤？', '["「廣泛」之定義，係指用以形容不實表達對財務報表之影響", "修正式意見之類型取決於，會計師就該事項對財務報表之影響或可能影響是否廣泛所作之判斷", "會計師已取得足夠及適切之查核證據，並認為不實表達（就個別或彙總而言）對財務報表之影 響係屬重大且廣泛，應表示保留意見", "會計師無法取得足夠及適切之查核證據以作為表示查核意見之基礎，並認為未偵出不實表達對 財務報表之可能影響係屬重大且廣泛，應出具無法表示意見之查核報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00282', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '有關會計師事務所品質管制之敘述，下列何者錯誤？', '["事務所品質管制制度如有缺失，並不表示所出具之查核報告不適當", "事務所建立品質管制制度之目標之一為合理確信事務所及其人員已遵循專業準則及法令", "每位事務所人員均對品質負有責任", "同一非上市（櫃）公司之確信服務案件，如長期由相同資深人員執行，亦應訂定標準予以輪調"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00283', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '查核人員應執行風險評估程序，作為辨識並評估財務報表之重大不實表達風險的基礎。下列敘述 何者錯誤？', '["風險評估程序是經由對受查者及其環境之瞭解，辨識並評估導因於錯誤或舞弊之整體財務報表 及個別項目聲明之重大不實表達風險，所執行之查核程序", "風險評估程序應包含查詢受查人相關人員、分析性程序以及函證", "重大不實表達風險是財務報表在查核前即存在之風險", "個別項目之重大不實表達風險由控制風險與固有風險組成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
